{
  "name": "DOFTA - The Farmer's Digital Co-operative",
  "description": "A comprehensive frontend MVP for DOFTA, a decentralized, AI-driven agricultural platform where farmers and buyers co-own, co-govern, and co-profit. This clickable demo showcases the platform's value proposition to clients, partners, and investors."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { UserRole, Screen } from './types';
import Onboarding from './components/Onboarding';
import FarmerDashboard from './components/FarmerDashboard';
import BuyerDashboard from './components/BuyerDashboard';
import Monitoring from './components/Monitoring';
import Wallet from './components/Wallet';
import Marketplace from './components/Marketplace';
import CarbonMinting from './components/CarbonMinting';
import DeFiPortal from './components/DeFiPortal';
import Governance from './components/Governance';
import BottomNav from './components/shared/BottomNav';
import Header from './components/shared/Header';

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.Dashboard);

  const handleOnboardingComplete = useCallback((role: UserRole) => {
    setUserRole(role);
  }, []);

  const renderContent = () => {
    switch (currentScreen) {
      case Screen.Dashboard:
        return userRole === UserRole.Farmer ? <FarmerDashboard navigate={setCurrentScreen} /> : <BuyerDashboard navigate={setCurrentScreen} />;
      case Screen.Monitoring:
        return <Monitoring />;
      case Screen.Wallet:
        return <Wallet />;
      case Screen.Marketplace:
        return <Marketplace userRole={userRole!} />;
      case Screen.Carbon:
        return <CarbonMinting navigate={setCurrentScreen} />;
      case Screen.DeFi:
        return <DeFiPortal />;
      case Screen.Governance:
        return <Governance />;
      default:
        return userRole === UserRole.Farmer ? <FarmerDashboard navigate={setCurrentScreen} /> : <BuyerDashboard navigate={setCurrentScreen} />;
    }
  };

  if (!userRole) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  const isMobileView = userRole === UserRole.Farmer;

  return (
    <div className={`flex flex-col h-screen font-sans antialiased ${isMobileView ? 'bg-stone-100' : 'bg-white'}`}>
       <div className={`${isMobileView ? 'w-full max-w-lg mx-auto' : ''} flex flex-col h-full`}>
        <Header userRole={userRole} />
        <main className="flex-grow overflow-y-auto pb-24 px-4 md:px-6 lg:px-8">
          {renderContent()}
        </main>
        {isMobileView && <BottomNav currentScreen={currentScreen} setCurrentScreen={setCurrentScreen} />}
       </div>
    </div>
  );
};

export default App;

export enum UserRole {
  Farmer = 'FARMER',
  Buyer = 'BUYER',
}

export enum Screen {
  Dashboard = 'DASHBOARD',
  Monitoring = 'MONITORING',
  Wallet = 'WALLET',
  Marketplace = 'MARKETPLACE',
  Carbon = 'CARBON',
